#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 1000000000
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int qp(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
		a=a*a;
		b>>=1;
	}
	return ans;
}
int l[140005],r[140005],a[140005],k;
char c;
void d1(int i)
{
	cout<<i<<' ';
	if(!l[i])
	{
		return;
	}
	if(l[i]>r[i]&&k)
	{
		swap(l[i],r[i]);
		k--;
	}
	d1(l[i]);
	d1(r[i]);
}
void d2(int i)
{
	if(!l[i])
	{
		return;
	}
	a[l[i]]=a[i];//预处理
	d2(l[i]);
	a[r[i]]=a[i]+1;
	d2(r[i]);
}
int d4(int i,int lim)
{
	if(!l[i])
	{
		return a[i]<=lim?i:inf;
	}
	return min(d4(l[i],lim),d4(r[i],lim));
}
void d3(int i)
{
	if(!l[i])
	{
		cout<<i<<' ';
		return;
	}
	int x=d4(l[i],k+a[i]);
	int y=d4(r[i],k+a[i]);
	if(x>y)
	{
		swap(l[i],r[i]);
		k--;
	}
	d3(l[i]);
	if(c=='B')
	{
		cout<<i<<' ';
		d3(r[i]);
	}
	else
	{
		d3(r[i]);
		cout<<i<<' ';
	}
}
signed main(void)
{
	IOS
	int n,rt,i;
	cin>>c>>n>>rt>>k;
	FOR(i,1,n)
	{
		cin>>l[i]>>r[i];
	}
	if(c=='A')
	{
		d1(rt);
	}
	else
	{
		d2(rt);
		d3(rt);//DFS求答案
	}
	return false;
}
